  "corrected_code": "package org.example.app.banji;

import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

@WebServlet("/sample020")
public class Sample020 extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        request.setCharacterEncoding("UTF-8");
        response.setContentType("application/json;charset=UTF-8");

        String op = request.getParameter("op");
        if (op == null || op.isEmpty()) {
            response.getWriter().write("{\"error\":\"Missing operation parameter\"}");
            return;
        }

        BanjiDao banjiDao = new BanjiDao();

        if ("selectAll".equals(op)) {
            String result = banjiDao.selectAll();
            // Escape or sanitize result if it may contain user-generated content
            response.getWriter().write(result);

        } else if ("add".equals(op)) {
            String banji_name = request.getParameter("banji_name");
            String zhuanye = request.getParameter("zhuanye");
            String fudaoyuan = request.getParameter("fudaoyuan");
            String renshuStr = request.getParameter("renshu");

            // Validate required fields
            if (banji_name == null || banji_name.isEmpty() ||
                zhuanye == null || zhuanye.isEmpty() ||
                fudaoyuan == null || fudaoyuan.isEmpty()) {
                response.getWriter().write("{\"error\":\"Missing required fields\"}");
                return;
            }

            int renshu = 0;
            if (renshuStr != null && !renshuStr.isEmpty()) {
                try {
                    renshu = Integer.parseInt(renshuStr);
                    if (renshu < 0) {
                        response.getWriter().write("{\"error\":\"Renshu must be non-negative\"}");
                        return;
                    }
                } catch (NumberFormatException e) {
                    response.getWriter().write("{\"error\":\"Invalid renshu value\"}");
                    return;
                }
            }

            BanjiBean bean = new BanjiBean();
            bean.setBanji_name(banji_name);
            bean.setZhuanye(zhuanye);
            bean.setFudaoyuan(fudaoyuan);
            bean.setRenshu(renshu);

            banjiDao.save(bean);
            response.getWriter().write("{\"success\":true}");
        } else {
            response.getWriter().write("{\"error\":\"Unknown operation\"}");
        }
    }

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        // GET requests should not perform state-changing operations
        response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "GET method not supported");
    }
}"
}
